import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Creating a fixed-size buffer
        char[] buffer = new char[10];

        // Copying user input into the fixed-size buffer with bounds checking
        int length = Math.min(userInput.length(), buffer.length); // Choose minimum of user input length and buffer size
        userInput.getChars(0, length, buffer, 0); // Copy characters from user input to buffer

        System.out.println("Buffer overflow vulnerability fixed!");
    }
}

